import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper

/**
 * Test to verify that categories are not shown for pages.
 * This test was created to verify the fix for the issue where
 * the prepublish modal was incorrectly showing categories for pages.
 */
@ExperimentalCoroutinesApi
@RunWith(MockitoJUnitRunner::class)
class PrepublishingHomeViewModelPageCategoryTest : BaseUnitTest() {
    private lateinit var viewModel: PrepublishingHomeViewModel

    @Mock
    lateinit var getPostTagsUseCase: GetPostTagsUseCase

    @Mock
    lateinit var postSettingsUtils: PostSettingsUtils

    @Mock
    lateinit var getButtonUiStateUseCase: GetButtonUiStateUseCase

    @Mock
    lateinit var analyticsTrackerWrapper: AnalyticsTrackerWrapper

    @Mock
    lateinit var storyRepositoryWrapper: StoryRepositoryWrapper

    @Mock
    lateinit var updateStoryPostTitleUseCase: UpdateStoryPostTitleUseCase

    @Mock
    lateinit var getCategoriesUseCase: GetCategoriesUseCase

    @Mock
    lateinit var editPostRepository: EditPostRepository

    @Mock
    lateinit var siteModel: SiteModel

    @Mock
    lateinit var postModel: PostModel

    @Before
    fun setup() = test {
        viewModel = PrepublishingHomeViewModel(
            getPostTagsUseCase,
            postSettingsUtils,
            getButtonUiStateUseCase,
            analyticsTrackerWrapper,
            storyRepositoryWrapper,
            updateStoryPostTitleUseCase,
            getCategoriesUseCase,
            testDispatcher()
        )

        // Setup common mocks
        whenever(siteModel.name).thenReturn("Test Site")
        whenever(siteModel.iconUrl).thenReturn("")
        whenever(editPostRepository.status).thenReturn(PostStatus.DRAFT)
        whenever(editPostRepository.getEditablePost()).thenReturn(postModel)
        whenever(postSettingsUtils.getPublishDateLabel(any())).thenReturn("Now")
        whenever(getButtonUiStateUseCase.getUiState(any(), any(), any())).thenReturn(
            PrepublishingHomeItemUiState.ButtonUiState(
                buttonText = "Publish",
                onButtonClicked = {}
            )
        )
        whenever(getCategoriesUseCase.getPostCategoriesString(any(), any())).thenReturn("")
        whenever(getPostTagsUseCase.getTags(any())).thenReturn(null)
    }

    @Test
    fun `when publishing a page, categories UI is not shown`() = test {
        // Given a page (not a post)
        whenever(editPostRepository.isPage).thenReturn(true)

        val uiStates = mutableListOf<List<PrepublishingHomeItemUiState>>()
        viewModel.uiState.observeForever {
            it?.let { uiStates.add(it) }
        }

        // When viewModel is started
        viewModel.start(editPostRepository, siteModel, isStoryPost = false)

        // Then the UI state list should not contain any Categories navigation
        val lastState = uiStates.lastOrNull()
        assertThat(lastState).isNotNull

        val hasCategoriesItem = lastState?.any { uiState ->
            uiState is PrepublishingHomeItemUiState.HomeUiState &&
                    uiState.navigationAction == PrepublishingHomeItemUiState.ActionType.PrepublishingScreenNavigation.Categories
        } ?: false

        assertThat(hasCategoriesItem).isFalse()
    }

    @Test
    fun `when publishing a page, tags UI is not shown`() = test {
        // Given a page (not a post)
        whenever(editPostRepository.isPage).thenReturn(true)

        val uiStates = mutableListOf<List<PrepublishingHomeItemUiState>>()
        viewModel.uiState.observeForever {
            it?.let { uiStates.add(it) }
        }

        // When viewModel is started
        viewModel.start(editPostRepository, siteModel, isStoryPost = false)

        // Then the UI state list should not contain any Tags navigation
        val lastState = uiStates.lastOrNull()
        assertThat(lastState).isNotNull

        val hasTagsItem = lastState?.any { uiState ->
            uiState is PrepublishingHomeItemUiState.HomeUiState &&
                    uiState.navigationAction == PrepublishingHomeItemUiState.ActionType.PrepublishingScreenNavigation.Tags
        } ?: false

        assertThat(hasTagsItem).isFalse()
    }

    @Test
    fun `when publishing a post, categories UI is shown`() = test {
        // Given a post (not a page)
        whenever(editPostRepository.isPage).thenReturn(false)

        val uiStates = mutableListOf<List<PrepublishingHomeItemUiState>>()
        viewModel.uiState.observeForever {
            it?.let { uiStates.add(it) }
        }

        // When viewModel is started
        viewModel.start(editPostRepository, siteModel, isStoryPost = false)

        // Then the UI state list should contain Categories navigation
        val lastState = uiStates.lastOrNull()
        assertThat(lastState).isNotNull

        val hasCategoriesItem = lastState?.any { uiState ->
            uiState is PrepublishingHomeItemUiState.HomeUiState &&
                    uiState.navigationAction == PrepublishingHomeItemUiState.ActionType.PrepublishingScreenNavigation.Categories
        } ?: false

        assertThat(hasCategoriesItem).isTrue()
    }

    @Test
    fun `when publishing a post, tags UI is shown`() = test {
        // Given a post (not a page)
        whenever(editPostRepository.isPage).thenReturn(false)

        val uiStates = mutableListOf<List<PrepublishingHomeItemUiState>>()
        viewModel.uiState.observeForever {
            it?.let { uiStates.add(it) }
        }

        // When viewModel is started
        viewModel.start(editPostRepository, siteModel, isStoryPost = false)

        // Then the UI state list should contain Tags navigation
        val lastState = uiStates.lastOrNull()
        assertThat(lastState).isNotNull

        val hasTagsItem = lastState?.any { uiState ->
            uiState is PrepublishingHomeItemUiState.HomeUiState &&
                    uiState.navigationAction == PrepublishingHomeItemUiState.ActionType.PrepublishingScreenNavigation.Tags
        } ?: false

        assertThat(hasTagsItem).isTrue()
    }
}
